// --- 5. Image Editing ---

export const editMedicalImage = async (base64Image: string, editPrompt: string): Promise<string | null> => {
  try {
     const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
     const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, '');

     const response = await ai.models.generateContent({
       model: 'gemini-2.5-flash-image',
       contents: {
         parts: [
           { inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } },
           { text: editPrompt }
         ]
       }
     });

     for (const part of response.candidates?.[0]?.content?.parts || []) {
       if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
     }
     return null;
  } catch (error) {
    console.error("Image Edit Error:", error);
    return null;
  }
};

// --- 6. Anatomy/Visual Gen (Gemini 3 Pro Image) ---

export const generateAnatomyImage = async (prompt: string, size: '1K' | '2K' | '4K'): Promise<string | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: `Medical illustration: ${prompt}. Anatomically correct, educational style.` }] },
      config: { imageConfig: { imageSize: size, aspectRatio: "1:1" } },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) {
    console.error("Anatomy Gen Error:", error);
    throw error;
  }
};

export const generateVisualContent = async (topic: string, format: string, aspectRatio: string = "1:1"): Promise<string | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let promptDetail = format === 'Infografía' 
        ? `Medical Infographic about "${topic}". Clean, informative layout, medical blue palette. Text must be legible.` 
        : `Medical Decision Flowchart/Algorithm about "${topic}". Professional, white background, high contrast text.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: promptDetail }] },
      config: { 
        imageConfig: { 
          imageSize: "1K", 
          aspectRatio: (aspectRatio as any) || "1:1" 
        } 
      },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) {
    console.error("Visual Gen Error:", error);
    throw error;
  }
};

export const generateResearchMap = async (topic: string): Promise<string | null> => {
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Create a detailed 'Knowledge Graph' or 'Citation Network Map' (style of ResearchRabbit) about the topic: "${topic}".

        VISUAL REQUIREMENTS:
        - White background, professional scientific look.
        - Central nodes: Seminal/Foundational papers (labeled with Author/Year, e.g., 'Smith 2015').
        - Peripheral nodes: Recent 2024-2025 papers connecting to the center.
        - Use colored lines to show connections (citations).
        - Clusters: Group by sub-themes (e.g., Diagnosis, Treatment, Outcomes).
        - Text MUST BE LEGIBLE. High contrast.
        - Title at the top: 'Estado del Arte: ${topic}'.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-image-preview',
            contents: { parts: [{ text: prompt }] },
            config: { imageConfig: { imageSize: "1K", aspectRatio: "16:9" } },
        });

        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
        return null;
    } catch (error) {
        console.error("Research Map Error:", error);
        throw error; // Let UI handle the error
    }
};

// --- 8. OPEN EVIDENCE / FAST CHECK ---

export const consultEAUFastCheck = async (query: string): Promise<{pearl: string, evidence: string, sources: string} | null> => {
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // OPEN EVIDENCE STYLE PROMPT
        // Searches broadly for high-quality evidence, prioritizing guidelines but not limited to strict "2025" string matching if unavailable.
        const prompt = `
        ACTÚA COMO UN MOTOR DE EVIDENCIA MÉDICA (tipo Open Evidence).
        Consulta del usuario: "${query}".

        REALIZA UNA BÚSQUEDA EXHAUSTIVA EN: Guías Clínicas (EAU, AUA, NCCN) y Literatura Reciente (2023-2025).

        Objetivo: Responder con certeza clínica y fuentes.

        Devuelve JSON PURO (sin markdown):
        {
            "pearl": "La respuesta directa y concisa en 1-2 frases (La Perla Clínica).",
            "evidence": "Explicación detallada justificando la respuesta con datos (HR, p-values, grados de recomendación si existen).",
            "sources": "Lista de Guías o Artículos específicos encontrados (ej. EAU Guidelines 2024, EAU Pocket 2025, AUA 2023)."
        }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
            }
        });

        if (response.text) {
             let cleanText = response.text.replace(/```json/g, '').replace(/```/g, '').trim();
             const result = JSON.parse(cleanText);
             // Normalize keys in case model drifts
             return {
                 pearl: result.pearl || result.answer || "Sin respuesta concisa.",
                 evidence: result.evidence || result.shield || result.explanation || "Sin detalle.",
                 sources: result.sources || result.reference || "Fuentes generales."
             };
        }
        return null;
    } catch (error) {
        console.error("Evidence Check Error", error);
        return null;
    }
}

// --- 9. News Fetcher ---

export const fetchUrologyNews = async (): Promise<{title: string, time: string, tag: string, url: string}[]> => {
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Busca 4 noticias recientes de Urología (últimas 48h).
        Devuelve un array JSON PURO (sin markdown):
        [{"title": "Titular", "time": "hace X h", "tag": "Tema", "url": "http..."}]
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
            }
        });

        if (response.text) {
            let cleanText = response.text.replace(/```json/g, '').replace(/```/g, '').trim();
            const parsed = JSON.parse(cleanText);
            if (Array.isArray(parsed)) return parsed.slice(0, 4);
        }
        return [];
    } catch (error) {
        console.error("News Fetch Error", error);
        return [];
    }
}

import React, { useState } from 'react';
import { generateVisualContent } from '../services/geminiService';
import { Workflow, Loader2, Download, Image as ImageIcon, Layout, AlertTriangle, Wand2, Maximize, Smartphone, Square } from 'lucide-react';

const VisualStudio: React.FC = () => {
    const [topic, setTopic] = useState('');
    const [format, setFormat] = useState('Algoritmo de Decisión');
    const [aspectRatio, setAspectRatio] = useState('16:9');
    const [resultImage, setResultImage] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleGenerate = async (isRetry = false) => {
        if (!topic) return;
        setLoading(true);
        if (!isRetry) setError(null);
        setResultImage(null);

        // Pre-emptive check: if we know we don't have a key, ask for one before trying
        if (!isRetry && (window as any).aistudio && (window as any).aistudio.hasSelectedApiKey) {
            const hasKey = await (window as any).aistudio.hasSelectedApiKey();
            if (!hasKey) {
                try {
                    if ((window as any).aistudio.openSelectKey) {
                        await (window as any).aistudio.openSelectKey();
                    }
                } catch (e) {
                    setError("Se requiere clave API para generar imágenes.");
                    setLoading(false);
                    return;
                }
            }
        }

        try {
            const img = await generateVisualContent(topic, format, aspectRatio);
            setResultImage(img);
        } catch (err: any) {
            console.error("Visual Generation Error:", err);

            // Robust error checking for 403 / Permission Denied
            const errorMsg = err.message || err.toString() || JSON.stringify(err);
            const isPermissionError = errorMsg.includes("403") || 
                                      errorMsg.includes("PERMISSION_DENIED") || 
                                      errorMsg.includes("permission");

            if (isPermissionError) {
                // If we already retried once and failed again, show specific error
                if (isRetry) {
                     setError("Permiso denegado. Por favor, selecciona un proyecto de Google Cloud con facturación habilitada para usar Gemini 3 Pro.");
                     setLoading(false);
                     return;
                }

                // Trigger key selection and retry
                 try {
                     if ((window as any).aistudio && (window as any).aistudio.openSelectKey) {
                         await (window as any).aistudio.openSelectKey();
                         // Recursive retry after key selection
                         await handleGenerate(true);
                         return; // Return to prevent setting loading=false prematurely
                     } else {
                         setError("Permiso denegado. Este modelo requiere una clave API de un proyecto pago.");
                     }
                 } catch (retryErr) {
                     setError("No se pudo seleccionar la clave API. Inténtalo de nuevo.");
                 }
            } else {
                setError("Error al generar el visual: " + (err.message || "Inténtalo de nuevo."));
            }
        }
        setLoading(false);
    };

    const aspectRatios = [
        { id: '16:9', label: 'Horizontal (16:9)', icon: Maximize },
        { id: '9:16', label: 'Vertical (9:16)', icon: Smartphone },
        { id: '3:4', label: 'Vertical Pro (3:4)', icon: Smartphone }, // Closest supported to 1:2
        { id: '1:1', label: 'Cuadrado (1:1)', icon: Square },
    ];

    return (
        <div className="p-6 max-w-6xl mx-auto animate-slide-up">
            <div className="mb-8">
                <h2 className="text-3xl font-bold text-slate-900 flex items-center gap-3">
                    <Workflow className="text-teal-600" size={32} />
                    Visual Studio
                </h2>
                <p className="text-slate-600">Creación de algoritmos, esquemas e infografías médicas mediante IA Generativa.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Control Panel */}
                <div className="lg:col-span-1 space-y-6">
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                        <label className="block text-sm font-bold text-slate-900 mb-2">Patología / Tema Clínico</label>
                        <textarea
                            value={topic}
                            onChange={(e) => setTopic(e.target.value)}
                            placeholder="Ej. Algoritmo de manejo de Microhematuria según AUA 2025..."
                            className="w-full h-32 p-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-teal-500 focus:outline-none resize-none text-sm mb-4"
                        />

                        <label className="block text-sm font-bold text-slate-900 mb-2">Formato Visual</label>
                        <div className="grid grid-cols-1 gap-2 mb-6">
                            {['Algoritmo de Decisión', 'Infografía', 'Esquema Anatómico', 'Diagrama de Flujo'].map((f) => (
                                <button
                                    key={f}
                                    onClick={() => setFormat(f)}
                                    className={`px-4 py-3 rounded-xl text-sm font-medium border text-left flex items-center gap-2 transition-all ${
                                        format === f 
                                        ? 'bg-teal-50 border-teal-500 text-teal-800 ring-1 ring-teal-500/20' 
                                        : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
