                            {mode === 'CREATE' ? <Workflow className="w-24 h-24 mx-auto mb-4 text-slate-400" /> : <ImagePlus className="w-24 h-24 mx-auto mb-4 text-slate-400" />}
                            <p className="text-xl font-bold text-slate-500">Lienzo Vacío</p>
