import { GoogleGenAI, Type, Modality } from "@google/genai";

// --- 1. Clinical & General Text Generation (Gemini 2.5 Flash for speed, 3 Pro for complex) ---

export const generateClinicalNote = async (prompt: string, complex: boolean = false): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const modelId = complex ? 'gemini-3-pro-preview' : 'gemini-2.5-flash';
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: "Eres un experto asistente urólogo. Genera documentación clínica estrictamente en TEXTO PLANO (Plain Text). ESTILO: Historia Clínica Electrónica (similar a Mambrino XXI). PROHIBIDO USAR MARKDOWN (nada de negritas '**', nada de cursivas, nada de símbolos extraños). Usa saltos de línea para separar secciones. El objetivo es que el texto se pueda copiar y pegar directamente en un software médico antiguo. Usar mayúsculas SOLO para los títulos de las secciones. El contenido del cuerpo debe usar gramática estándar (tipo oración).",
        temperature: 0.2,
      }
    });
    return response.text || "Error al generar la nota.";
  } catch (error) {
    console.error("Clinical Note Gen Error:", error);
    return "Error al generar la nota clínica. Por favor, verifica tu conexión e inténtalo de nuevo.";
  }
};

export const chatWithUrologistAI = async (history: { role: string, content: string }[], newMessage: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      history: history.map(h => ({ role: h.role, parts: [{ text: h.content }] })),
      config: {
        systemInstruction: `CONTEXTO TEMPORAL OBLIGATORIO: HOY ES 2 de Diciembre de 2025. Guías EAU/AUA 2025 publicadas. Eres UroEvidence Coach. Formato estándar, sin LaTeX.`,
      }
    });
    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Error en el chat.";
  }
};

// --- 4. Teaching Content (REDISEÑADO PARA PRESENTACIONES LARGAS) ---

export const generateTeachingContent = async (toolType: string, context: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let systemInstruction = "Eres un Profesor Titular de Urología y Diseñador Instruccional Senior. FECHA: Diciembre 2025. ";

    switch (toolType) {
        case 'ABSTRACT': systemInstruction += "Genera un Abstract estructurado para congreso."; break;
        case 'SESSION': systemInstruction += "Crea un esquema para Sesión Clínica con bibliografía reciente."; break;
        case 'EXAM': systemInstruction += "Crea preguntas tipo test basadas en guías."; break;
        case 'CLINICAL_CASE': systemInstruction += "Genera un CASO CLÍNICO DESAFIANTE."; break;
        case 'PRESENTATION': 
            systemInstruction += `
            ACTÚA COMO UN EXPERTO PONENTE EN CONGRESOS INTERNACIONALES DE UROLOGÍA.

            REGLA DE ORO DE EXTENSIÓN:
            - Si la duración es '10 min': 5-8 diapositivas (Mensajes clave).
            - Si la duración es '20 min': 12-18 diapositivas (Equilibrio).
            - Si la duración es '45-60 min': DEBES generar entre 30 y 45 diapositivas. Amplifica el contenido, profundiza en fisiopatología, estudios de fase II/III, subanálisis, controversias y futuro del campo. NO te quedes corto.

            REGLA DE AUDIENCIA:
            - Residentes: Explica el 'por qué', usa esquemas básicos, algoritmos de guías y perlas de examen.
            - Expertos: Ignora lo básico. Céntrate en data de alta calidad (NEJM, Lancet, JCO), p-values, HR, controversias en guías y medicina personalizada.

            ESTRUCTURA DE CADA DIAPOSITIVA (OBLIGATORIO):
            1. DIAPOSITIVA [NÚMERO]: [TÍTULO]
            2. DISEÑO Y MONTAJE: Sugerencias de layout (ej. 'Fondo oscuro, imagen a la izquierda'), transiciones recomendadas (ej. 'Fundido suave'), animaciones de entrada de bullets.
            3. ELEMENTOS VISUALES: Descripción de la imagen, gráfico de barras, tabla comparativa o diagrama de flujo necesario.
            4. CONTENIDO (Pantalla): Máximo 4-5 bullets con la información técnica más relevante.
            5. GUION DEL ORADOR (Script): Narrativa profesional y fluida para el ponente.
            6. PERLA DE INFORMACIÓN: Un dato crítico o "must-know" destacado.
            7. FRASE REFLEXIVA / PREGUNTA: Para mantener el engagement de la audiencia.
            8. BIBLIOGRAFÍA: Citas específicas según Vancouver o APA (EAU 2025, Trials clave como EMBARK, ENZAMET, etc.).

            Genera un guion EXHAUSTIVO. Si el tema es complejo, desarrolla sub-temas detalladamente.
            `; 
            break;
        default: systemInstruction += "Genera contenido educativo médico.";
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: context,
      config: { 
        systemInstruction, 
        temperature: 0.7, // Slightly higher for more creative slide suggestions
      }
    });

    return response.text || "Error generando contenido.";
  } catch (error) {
    console.error("Teaching Gen Error:", error);
    return "Error al generar contenido docente.";
  }
};

