export const generateClinicalNote = async (prompt: string, complex: boolean = false): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const modelId = complex ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: "Eres un experto asistente urólogo. Genera documentación clínica estrictamente en TEXTO PLANO. PROHIBIDO USAR MARKDOWN.",
        temperature: 0.2,
      }
    });
    return response.text || "Error al generar la nota.";
  } catch (error) {
    console.error("Clinical Note Gen Error:", error);
    return "Error al generar la nota clínica.";
  }
};

export const chatWithUrologistAI = async (history: { role: string, content: string }[], newMessage: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      history: history.map(h => ({ role: h.role === 'model' ? 'model' : 'user', parts: [{ text: h.content }] })),
      config: {
        systemInstruction: `CONTEXTO TEMPORAL OBLIGATORIO: Diciembre 2025. Guías EAU/AUA 2025.`,
