export const generateTeachingContent = async (
  toolType: string, 
  context: string, 
  fileData?: { data: string, mimeType: string }
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let systemInstruction = "Eres un Profesor Titular de Urología y Diseñador Instruccional Senior. FECHA: Diciembre 2025. ";

    switch (toolType) {
        case 'ABSTRACT': systemInstruction += "Genera un Abstract estructurado para congreso."; break;
        case 'SESSION': systemInstruction += "Crea un esquema para Sesión Clínica con bibliografía reciente."; break;
        case 'EXAM': systemInstruction += "Crea preguntas tipo test basadas en guías."; break;
        case 'CLINICAL_CASE': systemInstruction += "Genera un CASO CLÍNICO DESAFIANTE."; break;
        case 'PRESENTATION': 
            systemInstruction += `
            ACTÚA COMO UN EXPERTO PONENTE EN CONGRESOS INTERNACIONALES DE UROLOGÍA.
            SI SE ADJUNTA UN ARCHIVO (PDF O IMAGEN), UTILÍZALO COMO FUENTE PRINCIPAL. RESÚMELO Y TRANSFÓRMALO EN DIAPOSITIVAS VISUALES.

            REGLA DE ORO DE EXTENSIÓN:
            - '10 min': 5-8 diapositivas.
            - '20 min': 12-18 diapositivas.
            - '45-60 min': 30-45 diapositivas (Contenido masivo y detallado).

            ESTRUCTURA POR DIAPOSITIVA:
            1. DIAPOSITIVA [N]: [TÍTULO]
            2. DISEÑO Y MONTAJE: Layout, transiciones y animaciones.
            3. ELEMENTOS VISUALES: Descripción de gráficos o tablas necesarias basándote en el archivo.
            4. CONTENIDO (Texto en pantalla): 4-5 bullets técnicos.
            5. GUION (Script): Narrativa para el ponente.
            6. PERLA DE INFORMACIÓN / FRASE REFLEXIVA.
            7. BIBLIOGRAFÍA (Guías 2025).
            `; 
            break;
        default: systemInstruction += "Genera contenido educativo médico.";
    }

    const contents: any = [];
    if (fileData) {
        contents.push({
            inlineData: {
                data: fileData.data.split(',')[1], // Remove base64 header
                mimeType: fileData.mimeType
            }
        });
    }
    contents.push({ text: context });

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: contents },
      config: { 
        systemInstruction, 
        temperature: 0.7,
      }
    });

    return response.text || "Error generando contenido.";
  } catch (error) {
    console.error("Teaching Gen Error:", error);
    return "Error al generar contenido docente.";
  }
};

