export const generateClinicalNote = async (prompt: string, complex: boolean = false): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const modelId = complex ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: "Eres un experto urólogo. Genera texto plano sin markdown.",
        temperature: 0.2,
      }
    });
    return response.text || "";
  } catch { return ""; }
};

export const chatWithUrologistAI = async (history: { role: string, content: string }[], newMessage: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      history: history.map(h => ({ role: h.role === 'model' ? 'model' : 'user', parts: [{ text: h.content }] }))
    });
    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "";
  } catch { return ""; }
};

