import React, { useState, useRef } from 'react';
import { generateTeachingContent, evaluateClinicalCase } from '../services/geminiService';
// @ts-ignore
import PptxGenJS from 'pptxgenjs';
import { 
  BookOpen, 
  Presentation, 
  FileQuestion, 
  Terminal, 
  Lightbulb, 
  FileText, 
  Loader2, 
  Copy, 
  Check, 
  Microscope,
  Stethoscope,
  Projector,
  Info,
  FileUp,
  X,
  FileCheck,
  Download,
  FileBox
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';

type ToolType = 'ABSTRACT' | 'SESSION' | 'EXAM' | 'PROMPT' | 'TIPS' | 'EVIDENCE' | 'CLINICAL_CASE' | 'PRESENTATION';

const TeachingHub: React.FC = () => {
  const [activeTool, setActiveTool] = useState<ToolType>('ABSTRACT');
  const [inputContext, setInputContext] = useState('');
  const [generatedContent, setGeneratedContent] = useState('');

  const [caseTopic, setCaseTopic] = useState('');
  const [caseDifficulty, setCaseDifficulty] = useState('Residente R1-R2');
  const [userAnswer, setUserAnswer] = useState('');
  const [evaluation, setEvaluation] = useState('');
  const [caseStep, setCaseStep] = useState<'SETUP' | 'SCENARIO' | 'EVALUATION'>('SETUP');

  const [presTitle, setPresTitle] = useState('');
  const [presDuration, setPresDuration] = useState('20 min');
  const [presAudience, setPresAudience] = useState('Residentes');
  const [presStyle, setPresStyle] = useState('Científico y Visual');
  const [attachedFile, setAttachedFile] = useState<{data: string, mime: string, name: string} | null>(null);

  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [copied, setCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const tools = [
    { id: 'PRESENTATION', label: 'Presentación (Guion)', icon: Projector, placeholder: 'Generador de Guiones para PPT' },
    { id: 'ABSTRACT', label: 'Creación de Abstracts', icon: FileText, placeholder: 'Introduce los datos brutos del estudio...' },
    { id: 'SESSION', label: 'Sesiones Clínicas', icon: Presentation, placeholder: 'Tema de la sesión...' },
    { id: 'EXAM', label: 'Cuestionarios / Examen', icon: FileQuestion, placeholder: 'Tema y nivel de dificultad...' },
    { id: 'PROMPT', label: 'Ingeniero de Prompts', icon: Terminal, placeholder: 'Describe qué quieres lograr...' },
    { id: 'TIPS', label: 'Tips & Tricks Quirúrgicos', icon: Lightbulb, placeholder: 'Nombre del procedimiento...' },
    { id: 'EVIDENCE', label: 'Resumen Evidencia', icon: Microscope, placeholder: 'Pregunta clínica específica (PICO)...' },
    { id: 'CLINICAL_CASE', label: 'Reto Clínico (Interactivo)', icon: Stethoscope, placeholder: 'Tema del caso...' },
  ];

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAttachedFile({
          data: reader.result as string,
          mime: file.type,
          name: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    setLoading(true);
    setGeneratedContent('');

    if (activeTool === 'CLINICAL_CASE') {
        const prompt = `Genera un caso clínico sobre: ${caseTopic}. Nivel: ${caseDifficulty}.`;
        const result = await generateTeachingContent(activeTool, prompt);
        setGeneratedContent(result);
        setCaseStep('SCENARIO');
    } else if (activeTool === 'PRESENTATION') {
        const prompt = `
        TÍTULO PONENCIA: "${presTitle}"
        DURACIÓN: ${presDuration}
        AUDIENCIA: ${presAudience}
        ESTILO: ${presStyle}
        ${attachedFile ? `CONTEXTO ADJUNTO: Utiliza el archivo '${attachedFile.name}' para extraer data técnica, tablas y figuras.` : ''}
        `;
        const result = await generateTeachingContent(
          activeTool, 
          prompt, 
          attachedFile ? { data: attachedFile.data, mimeType: attachedFile.mime } : undefined
        );
        setGeneratedContent(result);
    } else {
        if (!inputContext) return;
        const result = await generateTeachingContent(activeTool, inputContext);
        setGeneratedContent(result);
    }

    setLoading(false);
  };

  const handleExportPPT = async () => {
    if (!generatedContent) return;
    setExporting(true);
    try {
      const pptx = new PptxGenJS();
      pptx.layout = 'LAYOUT_16x9';

      // Slide de Portada
      let slide = pptx.addSlide();
      slide.background = { color: '0F172A' }; // Slate 900
      slide.addText(presTitle || 'Ponencia Urología', { x: 0.5, y: 1.5, w: 9, fontSize: 44, color: 'FFFFFF', bold: true, align: 'center' });
      slide.addText('UroGenius AI Medical Suite | Diciembre 2025', { x: 0.5, y: 3.5, w: 9, fontSize: 18, color: '14B8A6', bold: true, align: 'center' });

      // Parsear diapositivas desde el contenido generado
      const slidesRaw = generatedContent.split('[SLIDE]').filter(s => s.trim().length > 0);

      slidesRaw.forEach((slideText) => {
        const newSlide = pptx.addSlide();

        // Extraer Título
        const titleMatch = slideText.match(/\[TITLE\]:\s*(.*)/);
        const title = titleMatch ? titleMatch[1].trim() : "Diapositiva";
        newSlide.addText(title, { x: 0.5, y: 0.3, w: 9, fontSize: 32, color: '0F172A', bold: true });

        // Extraer Contenido
        const contentMatch = slideText.match(/\[CONTENT\]:([\s\S]*?)\[VISUAL\]/);
        const content = contentMatch ? contentMatch[1].trim() : "";
        newSlide.addText(content, { x: 0.5, y: 1.2, w: 5, fontSize: 18, color: '334155', bullet: { indent: 20 } });

        // Extraer Notas del Orador
        const notesMatch = slideText.match(/\[NOTES\]:([\s\S]*?)\[DESIGN\]/);
        if (notesMatch) {
           newSlide.addNotes(notesMatch[1].trim());
        }

        // Diseño visual placeholder
        newSlide.addShape(pptx.ShapeType.rect, { x: 6, y: 1.2, w: 3.5, h: 3, fill: { color: 'F1F5F9' } });
        newSlide.addText("Sugerencia Visual:\n" + (slideText.match(/\[VISUAL\]:\s*(.*)/)?.[1] || "Imagen clínica"), { x: 6.2, y: 1.4, w: 3, fontSize: 12, color: '64748B', italic: true });

        // Perla
        const pearlMatch = slideText.match(/\[PEARL\]:\s*(.*)/);
        if (pearlMatch) {
          newSlide.addShape(pptx.ShapeType.rect, { x: 0.5, y: 4.5, w: 9, h: 0.8, fill: { color: 'E2E8F0' } });
          newSlide.addText(pearlMatch[1], { x: 0.7, y: 4.6, w: 8.6, fontSize: 14, color: '0F172A', bold: true, italic: true });
        }
      });

      await pptx.writeFile({ fileName: `${presTitle.replace(/\s/g, '_')}_UroGenius.pptx` });
    } catch (error) {
      console.error("Export Error:", error);
      alert("Error al exportar. Asegúrate de que el guion se haya generado correctamente.");
