import React, { useState, useRef } from 'react';
import { generateTeachingContent, evaluateClinicalCase } from '../services/geminiService';
// @ts-ignore
import PptxGenJS from 'pptxgenjs';
import { 
  BookOpen, 
  Presentation, 
  FileQuestion, 
  Terminal, 
  Lightbulb, 
  FileText, 
  Loader2, 
  Copy, 
  Check, 
  Microscope,
  Stethoscope,
  Projector,
  Info,
  FileUp,
  X,
  FileCheck,
  Download,
  FileBox
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';

type ToolType = 'ABSTRACT' | 'SESSION' | 'EXAM' | 'PROMPT' | 'TIPS' | 'EVIDENCE' | 'CLINICAL_CASE' | 'PRESENTATION';

const TeachingHub: React.FC = () => {
  const [activeTool, setActiveTool] = useState<ToolType>('ABSTRACT');
  const [inputContext, setInputContext] = useState('');
  const [generatedContent, setGeneratedContent] = useState('');

  const [caseTopic, setCaseTopic] = useState('');
  const [caseDifficulty, setCaseDifficulty] = useState('Residente R1-R2');
  const [userAnswer, setUserAnswer] = useState('');
  const [evaluation, setEvaluation] = useState('');
  const [caseStep, setCaseStep] = useState<'SETUP' | 'SCENARIO' | 'EVALUATION'>('SETUP');

  const [presTitle, setPresTitle] = useState('');
  const [presDuration, setPresDuration] = useState('20 min');
  const [presAudience, setPresAudience] = useState('Residentes');
  const [presStyle, setPresStyle] = useState('Científico y Visual');
  const [attachedFile, setAttachedFile] = useState<{data: string, mime: string, name: string} | null>(null);

  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [copied, setCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const tools = [
    { id: 'PRESENTATION', label: 'Presentación (Guion)', icon: Projector, placeholder: 'Generador de Guiones para PPT' },
    { id: 'ABSTRACT', label: 'Creación de Abstracts', icon: FileText, placeholder: 'Introduce los datos brutos del estudio...' },
    { id: 'SESSION', label: 'Sesiones Clínicas', icon: Presentation, placeholder: 'Tema de la sesión...' },
    { id: 'EXAM', label: 'Cuestionarios / Examen', icon: FileQuestion, placeholder: 'Tema y nivel de dificultad...' },
    { id: 'PROMPT', label: 'Ingeniero de Prompts', icon: Terminal, placeholder: 'Describe qué quieres lograr...' },
    { id: 'TIPS', label: 'Tips & Tricks Quirúrgicos', icon: Lightbulb, placeholder: 'Nombre del procedimiento...' },
    { id: 'EVIDENCE', label: 'Resumen Evidencia', icon: Microscope, placeholder: 'Pregunta clínica específica (PICO)...' },
    { id: 'CLINICAL_CASE', label: 'Reto Clínico (Interactivo)', icon: Stethoscope, placeholder: 'Tema del caso...' },
  ];

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAttachedFile({
          data: reader.result as string,
          mime: file.type,
          name: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  // Fix: Added missing resetCase function
  const resetCase = () => {
    setCaseTopic('');
    setCaseStep('SETUP');
    setGeneratedContent('');
    setUserAnswer('');
    setEvaluation('');
  };

  // Fix: Added missing handleEvaluate function
  const handleEvaluate = async () => {
    setLoading(true);
    const result = await evaluateClinicalCase(generatedContent, userAnswer);
    setEvaluation(result);
    setCaseStep('EVALUATION');
    setLoading(false);
  };

  const handleGenerate = async () => {
    setLoading(true);
    setGeneratedContent('');

    if (activeTool === 'CLINICAL_CASE') {
        const prompt = `Genera un caso clínico sobre: ${caseTopic}. Nivel: ${caseDifficulty}.`;
        const result = await generateTeachingContent(activeTool, prompt);
        setGeneratedContent(result);
        setCaseStep('SCENARIO');
    } else if (activeTool === 'PRESENTATION') {
        const prompt = `
        TÍTULO PONENCIA: "${presTitle}"
        DURACIÓN: ${presDuration}
        AUDIENCIA: ${presAudience}
        ESTILO: ${presStyle}
        ${attachedFile ? `CONTEXTO ADJUNTO: Utiliza el archivo '${attachedFile.name}' para extraer data técnica, tablas y figuras.` : ''}
        `;
        const result = await generateTeachingContent(
          activeTool, 
          prompt, 
          attachedFile ? { data: attachedFile.data, mimeType: attachedFile.mime } : undefined
        );
        setGeneratedContent(result);
    } else {
        if (!inputContext) return;
        const result = await generateTeachingContent(activeTool, inputContext);
        setGeneratedContent(result);
    }

    setLoading(false);
  };

  const handleExportPPT = async () => {
    if (!generatedContent) return;
    setExporting(true);
    try {
      const pptx = new PptxGenJS();
      pptx.layout = 'LAYOUT_16x9';

      // Slide de Portada
      let slide = pptx.addSlide();
      slide.background = { color: '0F172A' }; // Slate 900
      slide.addText(presTitle || 'Ponencia Urología', { x: 0.5, y: 1.5, w: 9, fontSize: 44, color: 'FFFFFF', bold: true, align: 'center' });
      slide.addText('UroGenius AI Medical Suite | Diciembre 2025', { x: 0.5, y: 3.5, w: 9, fontSize: 18, color: '14B8A6', bold: true, align: 'center' });

      // Parsear diapositivas desde el contenido generado
      const slidesRaw = generatedContent.split('[SLIDE]').filter(s => s.trim().length > 0);

      slidesRaw.forEach((slideText) => {
        const newSlide = pptx.addSlide();

        // Extraer Título
        const titleMatch = slideText.match(/\[TITLE\]:\s*(.*)/);
        const title = titleMatch ? titleMatch[1].trim() : "Diapositiva";
        newSlide.addText(title, { x: 0.5, y: 0.3, w: 9, fontSize: 32, color: '0F172A', bold: true });

        // Extraer Contenido
        const contentMatch = slideText.match(/\[CONTENT\]:([\s\S]*?)\[VISUAL\]/);
        const content = contentMatch ? contentMatch[1].trim() : "";
        newSlide.addText(content, { x: 0.5, y: 1.2, w: 5, fontSize: 18, color: '334155', bullet: { indent: 20 } });

        // Extraer Notas del Orador
        const notesMatch = slideText.match(/\[NOTES\]:([\s\S]*?)\[DESIGN\]/);
        if (notesMatch) {
           newSlide.addNotes(notesMatch[1].trim());
        }

        // Diseño visual placeholder
        newSlide.addShape(pptx.ShapeType.rect, { x: 6, y: 1.2, w: 3.5, h: 3, fill: { color: 'F1F5F9' } });
        newSlide.addText("Sugerencia Visual:\n" + (slideText.match(/\[VISUAL\]:\s*(.*)/)?.[1] || "Imagen clínica"), { x: 6.2, y: 1.4, w: 3, fontSize: 12, color: '64748B', italic: true });

        // Perla
        const pearlMatch = slideText.match(/\[PEARL\]:\s*(.*)/);
        if (pearlMatch) {
          newSlide.addShape(pptx.ShapeType.rect, { x: 0.5, y: 4.5, w: 9, h: 0.8, fill: { color: 'E2E8F0' } });
          newSlide.addText(pearlMatch[1], { x: 0.7, y: 4.6, w: 8.6, fontSize: 14, color: '0F172A', bold: true, italic: true });
        }
      });

      await pptx.writeFile({ fileName: `${presTitle.replace(/\s/g, '_')}_UroGenius.pptx` });
    } catch (error) {
      console.error("Export Error:", error);
      alert("Error al exportar. Asegúrate de que el guion se haya generado correctamente.");
    }
    setExporting(false);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const activeToolData = tools.find(t => t.id === activeTool);
  const isCaseMode = activeTool === 'CLINICAL_CASE';
  const isPresentationMode = activeTool === 'PRESENTATION';

  return (
    <div className="p-6 max-w-[1400px] mx-auto">
      <div className="mb-8 animate-slide-up">
        <h2 className="text-3xl font-bold text-slate-900">Docencia & I+D</h2>
        <p className="text-slate-600">Herramientas académicas para producción científica y educación médica continua.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-1 space-y-2 animate-slide-up delay-75">
          {tools.map((tool) => {
            const Icon = tool.icon;
            return (
              <button
                key={tool.id}
                onClick={() => { 
                    setActiveTool(tool.id as ToolType); 
                    setGeneratedContent(''); 
                    setInputContext('');
                    if (tool.id === 'CLINICAL_CASE') resetCase();
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold border ${
                  activeTool === tool.id
                    ? 'bg-slate-950 text-white border-slate-900 shadow-xl translate-x-1'
                    : 'bg-white text-slate-600 hover:bg-slate-100 border-slate-200'
                }`}
              >
                <Icon size={18} />
                {tool.label}
              </button>
            );
          })}
        </div>

        <div className="lg:col-span-3">
            {isCaseMode ? (
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 min-h-[500px] animate-slide-up">
                    <div className="flex items-center gap-2 mb-6 border-b border-slate-100 pb-4">
                        <div className="p-2 bg-teal-100 text-teal-700 rounded-lg"><Stethoscope size={24}/></div>
                        <div>
                            <h3 className="text-xl font-bold text-slate-900">Generador de Retos Clínicos</h3>
                            <p className="text-sm text-slate-500">Ponga a prueba a sus residentes.</p>
                        </div>
                    </div>
                    {caseStep === 'SETUP' && (
                        <div className="space-y-6 max-w-lg mx-auto py-8">
                            <div>
                                <label className="block text-sm font-bold text-slate-900 mb-2">Tema del Caso</label>
                                <input type="text" value={caseTopic} onChange={(e) => setCaseTopic(e.target.value)} placeholder="ej. Hematuria..." className="w-full p-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-teal-500 outline-none" />
                            </div>
                            <button onClick={handleGenerate} disabled={loading || !caseTopic} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2 disabled:opacity-50">
                                {loading ? <Loader2 className="animate-spin" /> : <Stethoscope size={18} />} Generar Caso
                            </button>
                        </div>
                    )}
                    {(caseStep === 'SCENARIO' || caseStep === 'EVALUATION') && (
                        <div className="grid grid-cols-1 gap-6">
                            <div className="bg-slate-50 p-6 rounded-xl border border-slate-200 prose prose-slate max-w-none">
                                <ReactMarkdown>{generatedContent}</ReactMarkdown>
                            </div>
                            {caseStep === 'SCENARIO' && (
                                <div className="space-y-4">
                                    <textarea value={userAnswer} onChange={(e) => setUserAnswer(e.target.value)} placeholder="Escribe aquí tu diagnóstico y plan..." className="w-full h-32 p-4 border border-slate-300 rounded-xl focus:ring-2 focus:ring-teal-500 outline-none resize-none" />
                                    <button onClick={handleEvaluate} disabled={loading || !userAnswer} className="w-full bg-teal-600 text-white py-3 rounded-xl font-bold hover:bg-teal-700 transition-all">
                                        Enviar Respuesta
                                    </button>
                                </div>
                            )}
                            {caseStep === 'EVALUATION' && (
                                <div className="animate-slide-up space-y-4">
                                    <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100 prose prose-indigo max-w-none text-sm">
                                        <ReactMarkdown>{evaluation}</ReactMarkdown>
                                    </div>
                                    <button onClick={resetCase} className="w-full bg-white border border-slate-300 text-slate-700 py-3 rounded-xl font-bold hover:bg-slate-50">Nuevo Caso</button>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            ) : isPresentationMode ? (
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-full animate-slide-up delay-100">
                    <div className="flex items-center gap-2 mb-6 border-b border-slate-100 pb-4">
                        <div className="p-2 bg-purple-100 text-purple-700 rounded-lg"><Projector size={24}/></div>
                        <div>
                            <h3 className="text-xl font-bold text-slate-900">Diseñador de Presentaciones PRO</h3>
                            <p className="text-sm text-slate-500">Genere guiones y exporte a PowerPoint directamente.</p>
                        </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6 items-start">
                        <div className="space-y-4 bg-slate-50 p-6 rounded-2xl border border-slate-200 sticky top-0">
                            <div>
                                <label className="block text-sm font-bold text-slate-900 mb-1">Título de la Ponencia</label>
                                <input type="text" value={presTitle} onChange={(e) => setPresTitle(e.target.value)} placeholder="Ej. Avances en Robótica..." className="w-full p-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none" />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-900 mb-1">Duración</label>
                                    <select value={presDuration} onChange={(e) => setPresDuration(e.target.value)} className="w-full p-3 border border-slate-300 rounded-xl bg-white focus:ring-2 focus:ring-purple-500 outline-none font-medium">
                                        <option>10 min (Flash)</option>
                                        <option>20 min (Estándar)</option>
                                        <option>45 min (Grand Rounds)</option>
                                        <option>60 min (Masterclass)</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-900 mb-1">Audiencia</label>
                                    <select value={presAudience} onChange={(e) => setPresAudience(e.target.value)} className="w-full p-3 border border-slate-300 rounded-xl bg-white focus:ring-2 focus:ring-purple-500 outline-none font-medium">
                                        <option>Residentes (Educativo)</option>
                                        <option>Especialistas (Avanzado)</option>
                                        <option>Médicos Generales (Divulgativo)</option>
                                        <option>Congreso Internacional (Expertos)</option>
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-900 mb-1">Estilo Visual</label>
                                <select value={presStyle} onChange={(e) => setPresStyle(e.target.value)} className="w-full p-3 border border-slate-300 rounded-xl bg-white focus:ring-2 focus:ring-purple-500 outline-none font-medium">
                                    <option>Científico y Riguroso</option>
                                    <option>Visual e Infográfico</option>
                                    <option>Controversias y Debate</option>
                                </select>
                            </div>

                            <div className="pt-2">
                                <label className="block text-sm font-bold text-slate-900 mb-2">Archivo de Referencia (PDF/Imagen)</label>
                                {!attachedFile ? (
                                  <button 
                                    onClick={() => fileInputRef.current?.click()}
                                    className="w-full flex items-center justify-center gap-2 p-4 border-2 border-dashed border-slate-300 rounded-xl text-slate-500 hover:border-purple-400 hover:bg-purple-50 transition-all text-xs font-bold"
                                  >
                                    <FileUp size={16} /> Adjuntar Documento Base
                                  </button>
                                ) : (
                                  <div className="flex items-center justify-between p-3 bg-white border border-purple-200 rounded-xl shadow-sm">
                                    <div className="flex items-center gap-2 overflow-hidden">
                                      <FileCheck className="text-purple-600 flex-shrink-0" size={18} />
                                      <span className="text-xs font-bold text-slate-700 truncate">{attachedFile.name}</span>
                                    </div>
                                    <button onClick={() => setAttachedFile(null)} className="p-1 hover:bg-red-50 text-red-500 rounded-full">
                                      <X size={16} />
                                    </button>
                                  </div>
                                )}
                                <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".pdf,.doc,.docx,image/*" className="hidden" />
                            </div>

                            <button onClick={handleGenerate} disabled={loading || !presTitle} className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-xl">
                                {loading ? <Loader2 className="animate-spin" /> : <Projector size={18} />} Generar Guion Estructurado
                            </button>
                        </div>
                        <div className="bg-white rounded-2xl p-6 overflow-y-auto max-h-[800px] min-h-[500px] border border-slate-200 shadow-xl relative custom-scrollbar">
                            {loading ? (
                                <div className="h-full flex flex-col items-center justify-center space-y-4 py-20">
                                    <Loader2 className="w-12 h-12 animate-spin text-purple-500" />
                                    <p className="text-slate-500 font-bold animate-pulse uppercase tracking-widest text-xs">Estructurando {presDuration} de contenido...</p>
                                </div>
                            ) : generatedContent ? (
                                <div className="prose prose-slate max-w-none prose-sm selection:bg-purple-500/30">
